# idea: concatenate types required to get into a cave with types required to get the treasure within the cave
# thus, if the cave is in a different location, use the new cave's types required with the treasure's types required
# for example, Shower Room requires yellow and blue Pikmin to access, but the Arboreal Frippery in the cave requires no specific type to get. 
# suppose the entrance to Shower Room is now at Subterranean Complex, which requires whites and blues to access.
# the types required to access the Arboreal Frippery would be ["white", "blue"] + [] = ["white", "blue"]. This will be used by the logic.
# So - for each cave treasure, we must check where the cave entrance has been placed, and then concatenate that cave's access requirements with the treasure's
# access requirements.
cave_pikmin_types_required = {
    "EC": [],
    "SC": ["blue", "white"],
    "FC": ["blue"],
    "HoB": [],
    "WFG": ["purple"],
    "BK": ["white", "yellow"],
    "SH": ["white", "blue"],
    "CoS": [],
    "GK": ["yellow"],
    "SR": ["yellow", "blue"],
    "SMGC": ["blue"],
    "CoC": [],
    "HoH": ["blue", "yellow"],
    "DD": ["blue", "white"]
}

